import React from 'react';
import { Container, Typography, Grid, Card, CardMedia } from '@mui/material';

function Gallery() {
  const images = [
    'https://via.placeholder.com/300x200?text=Women+Empowerment+1',
    'https://via.placeholder.com/300x200?text=Women+Empowerment+2',
    'https://via.placeholder.com/300x200?text=Women+Empowerment+3',
    'https://via.placeholder.com/300x200?text=Women+Empowerment+4',
    'https://via.placeholder.com/300x200?text=Women+Empowerment+5',
    'https://via.placeholder.com/300x200?text=Women+Empowerment+6'
  ];

  return (
    <Container maxWidth="lg" sx={{ mt: 4 }}>
      <Typography variant="h3" gutterBottom>
        Gallery
      </Typography>
      <Grid container spacing={2}>
        {images.map((image, index) => (
          <Grid item xs={12} sm={6} md={4} key={index}>
            <Card>
              <CardMedia
                component="img"
                height="200"
                image={image}
                alt={`Gallery image ${index + 1}`}
              />
            </Card>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
}

export default Gallery;