import React from 'react';
import { Container, Typography, Grid, Card, CardContent, CardMedia } from '@mui/material';

function Services() {
  const services = [
    {
      title: 'Education Support',
      description: 'Providing educational resources and scholarships to girls and women to ensure they have access to quality education.',
      image: 'https://via.placeholder.com/300x200?text=Education'
    },
    {
      title: 'Vocational Training',
      description: 'Offering skill development programs to help women acquire employable skills and achieve financial independence.',
      image: 'https://via.placeholder.com/300x200?text=Training'
    },
    {
      title: 'Healthcare Access',
      description: 'Ensuring women have access to essential healthcare services, including reproductive health and mental health support.',
      image: 'https://via.placeholder.com/300x200?text=Healthcare'
    },
    {
      title: 'Legal Aid',
      description: 'Providing legal assistance and counseling to women facing domestic violence, discrimination, or other legal issues.',
      image: 'https://via.placeholder.com/300x200?text=Legal+Aid'
    }
  ];

  return (
    <Container maxWidth="lg" sx={{ mt: 4 }}>
      <Typography variant="h3" gutterBottom>
        Our Services
      </Typography>
      <Grid container spacing={4}>
        {services.map((service, index) => (
          <Grid item xs={12} sm={6} md={3} key={index}>
            <Card>
              <CardMedia
                component="img"
                height="140"
                image={service.image}
                alt={service.title}
              />
              <CardContent>
                <Typography gutterBottom variant="h5" component="div">
                  {service.title}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {service.description}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
}

export default Services;